I'll search for Douyin financial content compliance rules and regulations. Let me start by exploring the workspace and then searching for relevant information.
[TOOL_CALL]
{tool => "Bash", args => {
  --description "Search for Douyin financial compliance rules"
  --command "cd /home/administrator && find . -type f -name \"*.md\" -o -name \"*.txt\" -o -name \"*.json\" 2>/dev/null | head -20"
  --timeout 30000
}}
[/TOOL_CALL]
[TOOL_CALL]
{tool => "WebFetch", args => {
  --description "Fetch Douyin financial content compliance regulations"
  --url "https://www.douyin.com/rule/dgy"
  --prompt "Extract all rules and regulations about financial content compliance on Douyin, including prohibited content, requirements, and guidelines"
  --timeout 30000
}}
[/TOOL_CALL]
[TOOL_CALL]
{tool => "WebSearch", args => {
  --description "Search for Douyin financial content compliance rules 2024-2025"
  --query "抖音 财经内容 合规规则 2024 2025 禁止 规定 抖音社区公约 金融"
  --recency_days 365
  --topn 10
}}
[/TOOL_CALL]
